module bitwise_and(
    input clk,
    input reset,
    input start,
    input [7:0] data1,
    input [7:0] data2,
    output reg [7:0] result,
    output reg done
);
    reg not_anding;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            result <= 8'd0;
            done <= 1'b0;
            not_anding <= 1'b0;
        end else if (start && !not_anding) begin
            not_anding <= 1'b1;
            done <= 1'b0;
        end else if (not_anding) begin
            result <= data1 & data2;
            not_anding <= 1'b0;
            done <= 1'b1;
        end
    end
endmodule
